const source = $input.first().json;
const jobId = source.jobId;
if (!jobId) throw new Error('Missing jobId for full visuals');
const text = source.text || {};
const order = source.order || {};
const chapters = (text.chapters || []).filter((chapter) => Number(chapter.n) > 1).sort((a, b) => Number(a.n) - Number(b.n));
const INTERIOR_IMAGE_TARGET = {
  role: 'interior_chapter_image_page',
  pageSizeMm: [136, 136],
  aspectRatio: '1:1',
  printDpiEquivalent: 'about 1606 x 1606 px at 300 DPI',
  placement: 'right-hand full-page chapter opener illustration',
  safety: 'full bleed square composition; keep faces, hands, key props and readable silhouettes away from the left 15% gutter/spine zone and the outer 3mm trim edge',
};
if (!chapters.length) throw new Error('No continuation chapters found for full visuals');

async function apiRequest(options) {
  return await this.helpers.httpRequest({
    ...options,
    headers: {
      Authorization: 'Bearer ' + $env.FAIRYTELLER_API_TOKEN,
      ...(options.headers || {}),
    },
    json: true,
  });
}

async function patchJob(body) {
  return await apiRequest.call(this, {
    method: 'PATCH',
    url: 'https://fairyteller.ru/api/fairyteller/jobs/' + jobId,
    headers: { 'Content-Type': 'application/json' },
    body,
    timeout: 30000,
  });
}

async function fetchJsonArtifact(fileName) {
  return await apiRequest.call(this, {
    method: 'GET',
    url: 'https://fairyteller.ru/api/fairyteller/jobs/' + jobId + '/artifacts/' + fileName,
    timeout: 30000,
  });
}

async function fetchVisualsArtifactWithRetry() {
  let lastError;
  for (let attempt = 1; attempt <= 18; attempt += 1) {
    try {
      const artifact = await fetchJsonArtifact.call(this, 'visuals.json');
      if (artifact?.visuals?.visualBible) return artifact;
      lastError = new Error('visuals.json exists but visualBible is missing');
    } catch (error) {
      lastError = error;
    }
    await new Promise((resolve) => setTimeout(resolve, 5000));
  }
  throw new Error('visuals.json was not ready for full visuals: ' + (lastError?.message || 'unknown error'));
}

async function fetchImageBase64(url) {
  if (!url) return null;
  const absoluteUrl = url.startsWith('http') ? url : 'https://fairyteller.ru' + url;
  const separator = absoluteUrl.includes('?') ? '&' : '?';
  const payload = await apiRequest.call(this, {
    method: 'GET',
    url: absoluteUrl + separator + 'base64=1',
    timeout: 30000,
  });
  if (!payload?.contentBase64) throw new Error('Fetched reference image has no base64 content');
  return { mimeType: payload.contentType || 'image/png', data: payload.contentBase64, bytes: payload.bytes || Buffer.from(payload.contentBase64, 'base64').length };
}

async function fetchReferenceImages(visuals, visualBible) {
  const cards = (visualBible?.heroReferenceCards || visuals.heroReferenceCards || []).filter((card) => card.status === 'ready' && card.url);
  const images = [];
  for (const card of cards) {
    const image = await fetchImageBase64.call(this, card.url);
    if (image?.data) {
      images.push({ ...image, type: 'hero_card', hero: card.hero, name: card.name || '', ageGroup: card.ageGroup || 'unknown', url: card.url });
    }
  }

  const expectedHeroCount = (visualBible?.characters || visuals.characters || order.heroes || [])
    .filter((hero) => hero?.name || hero?.description || hero?.referenceCardUrl || hero?.hasPhoto || hero?.ageGroup).length;
  const readyCardHeroCount = new Set(images.filter((image) => image.type === 'hero_card').map((image) => Number(image.hero))).size;
  const hasPortraitSheet = visuals.portraitSheet?.status === 'ready' && visuals.portraitSheet?.url;
  const needsPortraitSheet = hasPortraitSheet && (!images.length || (expectedHeroCount > 0 && readyCardHeroCount < expectedHeroCount));

  if (needsPortraitSheet) {
    const image = await fetchImageBase64.call(this, visuals.portraitSheet.url);
    if (image?.data) {
      images.push({ ...image, type: 'portrait_sheet', hero: null, name: 'combined reference sheet', ageGroup: 'mixed', url: visuals.portraitSheet.url });
    }
  }

  return images;
}

function referenceMapLines(referenceImages) {
  return referenceImages.map((image, index) => {
    if (image.type === 'hero_card') return 'Attached reference image ' + (index + 1) + ' = Hero ' + image.hero + ' (' + (image.name || 'unnamed') + '), age group ' + (image.ageGroup || 'unknown');
    return 'Attached reference image ' + (index + 1) + ' = combined hero reference sheet';
  }).join('\n');
}

function cleanText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function compactChapterText(chapter) {
  const raw = chapter.text || (Array.isArray(chapter.textBlocks) ? chapter.textBlocks.join(' ') : '');
  return cleanText(raw).slice(0, 1800);
}

function characterLine(hero) {
  const label = hero.name || ('Hero ' + (hero.hero || hero.n || ''));
  const age = hero.ageGroup || 'unknown';
  const ageNote = age === 'unknown' ? 'age group: unknown/infer from reference image' : 'age group: ' + age + ' (mandatory)';
  const ref = hero.referenceCardUrl ? 'reference card: ' + hero.referenceCardUrl : '';
  return [label, ageNote, ref, hero.description || '', hero.relation ? 'relation: ' + hero.relation : ''].filter(Boolean).join('; ');
}

function chapterPrompt(chapter, visualBible, referenceImages) {
  const bible = text.bible || {};
  const stylePrompt = visualBible?.style?.prompt || order.illustrationStylePrompt || order.illustrationStyle || 'photorealistic cinematic book illustration, realistic people, natural light, print-ready composition';
  const world = visualBible?.world || {};
  const characters = (visualBible?.characters || order.heroes || []).map((hero) => {
    if (hero.name || hero.description || hero.relation || hero.ageGroup) {
      return characterLine(hero);
    }
    return '';
  }).filter(Boolean).join('\n');
  const continuity = (visualBible?.consistencyRules || []).join(' ');
  const referenceMap = referenceMapLines(referenceImages || []);
  const hasHeroCards = (referenceImages || []).some((image) => image.type === 'hero_card');
  const hasPortraitSheet = (referenceImages || []).some((image) => image.type === 'portrait_sheet');
  const referenceInstruction = referenceImages?.length
    ? (hasHeroCards && hasPortraitSheet
      ? 'Use the attached individual hero reference cards where available, and use the attached combined character reference sheet for any hero whose individual card is missing. Treat both as mandatory identity canon; do not swap, merge, average or reinterpret identities. Preserve exact adult/child/teen/senior age groups, age impression, relative height scale, hair, proportions, outfits/accessories and role silhouettes.'
      : (hasHeroCards
        ? 'Use the attached individual hero reference cards as mandatory identity canon. Each card maps to exactly one hero; do not swap, merge, average or reinterpret identities. Preserve the same hero faces, exact adult/child/teen/senior age group, age impression, relative height scale, hair, proportions, outfits/accessories and role silhouettes from the cards.'
        : 'Use the attached generated character reference sheet as mandatory identity canon. Preserve the same hero faces, exact adult/child/teen/senior age group, age impression, height scale, hair, proportions, outfits/accessories and role silhouettes from the sheet. Do not reinterpret character identity from scratch.'))
    : 'No reference image is attached; preserve character identity from written descriptions and previous chapter continuity.';
  return [
    'Generate an IMAGE only. No explanatory text.',
    'Create a square 1:1 full-page book illustration for a 136 x 136 mm interior page for chapter ' + chapter.n + '.',
    'Absolutely no readable text inside the image: no chapter numbers, no chapter titles, no signs, no labels, no captions, no fake letters, no book-page typography, no posters, no banners, no UI. If the scene contains papers/books/signs, render them as abstract unreadable texture only.',
    '',
    '[PAGE TARGET]',
    'Final placement: ' + INTERIOR_IMAGE_TARGET.placement,
    'Page size: 136 x 136 mm, aspect ratio 1:1 square. At print scale this corresponds to about 1606 x 1606 px at 300 DPI.',
    'Fill the entire square page edge-to-edge; no letterboxing, no decorative frame, no landscape or portrait canvas. Do not leave white or blank margins. Treat the outer 3 mm and the left 15% gutter/spine side as unsafe for faces, hands, the important object and other must-read details.',
    '',
    '[STYLE - highest priority]',
    stylePrompt,
    '',
    '[CHARACTER IDENTITY]',
    referenceInstruction,
    referenceMap ? '[REFERENCE IMAGE MAP]\n' + referenceMap : '',
    '',
    '[VISUAL BIBLE CONTINUITY]',
    'Reference policy: ' + (visualBible?.referencePolicy || 'portrait_sheet_is_required_identity_canon'),
    'Consistency: ' + continuity,
    '',
    '[WORLD]',
    'World: ' + (world.title || bible.worldTitle || order.world || ''),
    'World visual language: ' + (world.visual || bible.worldVisual || ''),
    'World motifs: ' + (world.motifs || bible.worldMotifs || ''),
    'World tension: ' + (world.conflict || bible.worldConflict || ''),
    'Location continuity: ' + (world.location || order.location || bible.location || ''),
    'Important object continuity: ' + (world.artifact || order.artifact || bible.artifact || ''),
    '',
    '[CHAPTER SCENE]',
    'Chapter title for context only, do NOT render it: ' + (chapter.title || ('Глава ' + chapter.n)),
    'Scene summary: ' + (chapter.summary || ''),
    'Chapter text context: ' + compactChapterText(chapter),
    '',
    '[CHARACTERS]',
    characters || 'Use the main heroes from the story.',
    '',
    '[AGE AND ROLE RULE]',
    'Treat each hero age group as mandatory. Children must read as children, adults as adults, teenagers as teenagers, seniors as seniors. Keep relative height/scale and maturity stable; do not swap ages between heroes.',
    '',
    '[COMPOSITION]',
    'Pick one strong cinematic moment from this chapter, not a collage. Make the important object or world motif visible if it belongs in the scene. Use readable silhouettes, coherent anatomy, natural gestures, foreground-midground-background depth, and print-ready full-bleed square composition for a 136 x 136 mm page. This is not a poster and not a designed book page: no typography anywhere. This image will sit on the RIGHT page of an open spread; keep faces, hands, the important object, and readable silhouettes away from the left 15% inner gutter/spine zone and away from the outer 3mm trim edge. Do not put essential content in corners that can be trimmed.',
  ].filter((line) => line !== null && line !== undefined).join('\n');
}

function findInlineImage(response) {
  return (response.candidates?.[0]?.content?.parts || []).find((part) => part.inlineData?.data);
}

function responseText(response) {
  return (response.candidates?.[0]?.content?.parts || []).map((part) => part.text || '').join(' ').replace(/\s+/g, ' ').trim();
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function isRetryableGeminiError(error) {
  const status = Number(error?.response?.status || error?.statusCode || error?.status || 0);
  const message = String(error?.message || '');
  return status === 0 || status === 408 || status === 409 || status === 425 || status === 429 || status >= 500 || /timeout|ECONNRESET|ETIMEDOUT|socket|network/i.test(message);
}

async function geminiImageRequestWithRetry(request, label) {
  let lastError;
  for (let attempt = 1; attempt <= 4; attempt += 1) {
    try {
      return await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image:generateContent',
        headers: { 'x-goog-api-key': $env.GEMINI_API_KEY, 'Content-Type': 'application/json' },
        body: request,
        json: true,
        timeout: 180000,
      });
    } catch (error) {
      lastError = error;
      if (!isRetryableGeminiError(error) || attempt === 4) break;
      await sleep(6000 * attempt);
    }
  }
  throw new Error('Gemini image request failed for ' + label + ': ' + (lastError?.message || 'unknown error'));
}

async function generateChapterImage(chapter, visualBible, referenceImages) {
  const prompt = chapterPrompt(chapter, visualBible, referenceImages || []);
  const parts = [{ text: prompt }];
  for (const image of referenceImages || []) {
    if (image?.data) parts.push({ inlineData: { mimeType: image.mimeType || 'image/png', data: image.data } });
  }
  const request = {
    contents: [{ role: 'user', parts }],
    generationConfig: { responseModalities: ['TEXT', 'IMAGE'], temperature: 0.35 },
  };
  let response = await geminiImageRequestWithRetry.call(this, request, 'chapter ' + chapter.n + ' primary image');
  let part = findInlineImage(response);
  let textReason = responseText(response);
  if (!part) {
    const retryPrompt = [
      'Generate an IMAGE only. Do not answer with text.',
      'Book illustration for chapter ' + chapter.n + '. Title is context only, do NOT render words: ' + (chapter.title || ''),
      'Scene: ' + (chapter.summary || compactChapterText(chapter).slice(0, 500)),
      'Use the attached individual hero reference cards or combined character reference sheet as identity canon if present, including exact adult/child/teen/senior age roles and relative height scale. Do not swap hero identities.',
      'Style: ' + (visualBible?.style?.prompt || order.illustrationStylePrompt || order.illustrationStyle || 'book illustration'),
      'Target final page: 136 x 136 mm square interior page, 1:1 aspect ratio, full bleed edge-to-edge. No text or text-like marks, no letterboxing, no borders, no white margins, no blank paper background. Keep important faces and objects away from the left 15% inner gutter/spine zone and outer 3mm trim edge.',
    ].join('\n');
    response = await geminiImageRequestWithRetry.call(this, { contents: [{ role: 'user', parts: [{ text: retryPrompt }, ...(referenceImages || []).filter((image) => image?.data).map((image) => ({ inlineData: { mimeType: image.mimeType || 'image/png', data: image.data } }))] }], generationConfig: { responseModalities: ['TEXT', 'IMAGE'], temperature: 0.2 } }, 'chapter ' + chapter.n + ' simplified image');
    part = findInlineImage(response);
    textReason = responseText(response) || textReason;
  }
  if (!part) {
    throw new Error('Gemini did not return an inline image for chapter ' + chapter.n + ': ' + (textReason || response.promptFeedback?.blockReason || response.candidates?.[0]?.finishReason || 'unknown reason'));
  }
  const mimeType = part.inlineData.mimeType || 'image/png';
  const ext = mimeType.includes('webp') ? 'webp' : mimeType.includes('jpeg') || mimeType.includes('jpg') ? 'jpg' : 'png';
  const fileName = 'chapter-' + chapter.n + '.' + ext;
  await apiRequest.call(this, {
    method: 'PUT',
    url: 'https://fairyteller.ru/api/fairyteller/jobs/' + jobId + '/files/' + fileName,
    headers: { 'Content-Type': 'application/json' },
    body: { contentType: mimeType, contentBase64: part.inlineData.data },
    timeout: 60000,
  });
  const url = '/api/fairyteller/jobs/' + jobId + '/files/' + fileName;
  return {
    slot: 'chapter_' + chapter.n,
    chapter: Number(chapter.n),
    status: 'ready',
    fileName,
    url,
    absoluteUrl: 'https://fairyteller.ru' + url,
    mimeType,
    bytes: Buffer.from(part.inlineData.data, 'base64').length,
    prompt,
    provider: 'gemini',
    model: 'gemini-2.5-flash-image',
    targetPageSizeMm: INTERIOR_IMAGE_TARGET.pageSizeMm,
    targetAspectRatio: INTERIOR_IMAGE_TARGET.aspectRatio,
    role: 'interior_full_page_right_spread',
    referenceSheetUrl: visualBible?.portraitSheetUrl || null,
    characterReferenceCardUrls: (visualBible?.heroReferenceCards || []).map((card) => card.url).filter(Boolean),
    visualBibleVersion: visualBible?.version || 1,
  };
}

await patchJob.call(this, {
  artifacts: { fullVisuals: { status: 'generating', requestedAt: new Date().toISOString(), completed: 0, total: chapters.length } },
});

try {
  const existingArtifact = await fetchVisualsArtifactWithRetry.call(this);
  const existingVisuals = existingArtifact.visuals || {};
  const visualBible = existingVisuals.visualBible || {};
  const referenceImages = await fetchReferenceImages.call(this, existingVisuals, visualBible);

  const previousJobs = Array.isArray(existingVisuals.imageJobs) ? existingVisuals.imageJobs : [];
  const generatedImages = [];
  const fallbackImages = [];
  function publicImage(image) {
    const { prompt, ...publicImageValue } = image;
    return publicImageValue;
  }
  function fallbackSourceImage() {
    return [...generatedImages].reverse().find((image) => image.status === 'ready' && image.fileName)
      || previousJobs.find((image) => image.slot === 'chapter_1' && image.status === 'ready' && image.fileName)
      || previousJobs.find((image) => image.status === 'ready' && image.fileName);
  }
  for (const chapter of chapters) {
    let image;
    try {
      image = await generateChapterImage.call(this, chapter, visualBible, referenceImages);
    } catch (error) {
      const fallback = fallbackSourceImage();
      if (!fallback) throw error;
      const fallbackReason = String(error?.message || error || 'image generation failed').replace(/\s+/g, ' ').trim().slice(0, 600);
      image = {
        ...fallback,
        slot: 'chapter_' + chapter.n,
        chapter: Number(chapter.n),
        status: 'ready',
        fallback: true,
        fallbackFromSlot: fallback.slot || null,
        fallbackReason,
        prompt: chapterPrompt(chapter, visualBible, referenceImages || []),
        provider: fallback.provider || 'fallback_existing_image',
        model: fallback.model || 'existing_ready_image',
        role: 'interior_full_page_right_spread_fallback',
      };
      fallbackImages.push(publicImage(image));
    }
    generatedImages.push(image);
    await patchJob.call(this, {
      artifacts: { fullVisuals: { status: 'generating', completed: generatedImages.length, total: chapters.length, latestChapter: Number(chapter.n), images: generatedImages.map(publicImage), fallbackCount: fallbackImages.length, fallbacks: fallbackImages } },
    });
  }

  const replacedSlots = new Set(generatedImages.map((image) => image.slot));
  const imageJobs = [
    ...previousJobs.filter((image) => !replacedSlots.has(image.slot)),
    ...generatedImages,
  ].sort((a, b) => String(a.slot).localeCompare(String(b.slot), 'en', { numeric: true }));
  const visuals = {
    ...existingVisuals,
    imageJobs,
    imagePrompts: {
      ...(existingVisuals.imagePrompts || {}),
      ...Object.fromEntries(generatedImages.map((image) => [image.slot, image.prompt])),
    },
    fullVisuals: { status: 'ready', chapterCount: generatedImages.length, generatedAt: new Date().toISOString(), fallbackCount: fallbackImages.length, fallbacks: fallbackImages },
  };
  return [{ json: { ...source, status: 'full_visuals_ready', visuals, fullVisuals: { status: 'ready', chapterCount: generatedImages.length, images: generatedImages.map(publicImage), fallbackCount: fallbackImages.length, fallbacks: fallbackImages } } }];
} catch (error) {
  const message = 'Не удалось подготовить иллюстрации полной истории: ' + error.message;
  await patchJob.call(this, { artifacts: { fullVisuals: { status: 'failed', error: message } }, error: { message } });
  throw new Error(message);
}
